option.value:
package com.kalynx.serverlessreviewtool.git;

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.io.OutputStream;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.ArrayList;
import java.util.Comparator;
import java.util.List;
import java.util.Objects;
import java.util.stream.Stream;

/**
 * GitCommandNotes - Shell-level implementation of {@link GitNotesApi}.
 *
 * <p>All operations delegate to the {@code git} executable on the system PATH via
 * {@link ProcessBuilder}. The repository working directory is set for every command
 * so that callers can operate against multiple repositories without changing the JVM
 * working directory.
 *
 * <p>{@link #appendToStream} works in three steps:
 * <ol>
 *   <li>Loads the current stream content for the target ref if present.</li>
 *   <li>Appends one NDJSON line entry.</li>
 *   <li>Writes a new blob and points the stream ref at it via {@code git update-ref}.</li>
 * </ol>
 * This keeps each lane isolated while preserving full history inside the stream.
 */
public class GitCommandNotes implements GitNotesApi {

    private static final String FETCH_REFSPEC = "+" + NotesRef.wildcard() + ":" + NotesRef.wildcard();
    private static final String PUSH_REFSPEC = NotesRef.wildcard() + ":" + NotesRef.wildcard();
    private final RepositoryStore repositoryStore;

    /**
     * Creates an instance using the default local repository store root.
     */
    public GitCommandNotes() {
        this(new RepositoryStore(Paths.get(System.getProperty("user.home"), ".serverless-review-tool", "repositories")));
    }

    /**
     * Creates an instance using a custom repository store root path.
     *
     * @param storeRoot root directory used for local repository paths
     */
    public GitCommandNotes(Path storeRoot) {
        this(new RepositoryStore(storeRoot));
    }

    /**
     * Creates an instance with an explicit repository store implementation.
     *
     * @param repositoryStore repository store used to resolve repository paths
     */
    public GitCommandNotes(RepositoryStore repositoryStore) {
        this.repositoryStore = Objects.requireNonNull(repositoryStore, "repositoryStore");
    }

    /**
     * Returns a repository path from the configured repository store.
     *
     * @param repositoryKey unique key for the remote repository
     * @return absolute local path where the repository should be created
     * @throws GitException if the repository path cannot be prepared
     */
    public Path getOrCreateRepositoryPath(String repositoryKey) throws GitException {
        return repositoryStore.getOrCreateRepositoryPath(repositoryKey);
    }

    /**
     * Bootstraps notes for a repository key using the configured repository store.
     *
     * @param repositoryKey unique key for the remote repository
     * @param remote remote name
     * @param remoteUrl remote URL
     * @return absolute local path used for the repository
     * @throws GitException if bootstrap fails
     */
    public Path ensureNotesRepository(String repositoryKey, String remote, String remoteUrl) throws GitException {
        Path repoPath = repositoryStore.getOrCreateRepositoryPath(repositoryKey);
        this.cloneNotesRepository(repoPath, remote, remoteUrl);
        return repoPath;
    }

    /**
     * Removes a repository by key from the configured repository store.
     *
     * @param repositoryKey unique key for the remote repository
     * @throws GitException if deletion fails
     */
    public void removeRepository(String repositoryKey) throws GitException {
        removeRepository(repositoryStore.resolveRepositoryPath(repositoryKey));
    }

    /**
     * Clones only review notes refs into the target local repository path.
     *
     * @param repoPath repository root
     * @param remote remote name
     * @param remoteUrl remote URL
     * @throws GitException if clone/bootstrap commands fail
     */
    @Override
    public void cloneNotesRepository(Path repoPath, String remote, String remoteUrl) throws GitException {
        ensureDirectory(repoPath);
        ensureGitRepository(repoPath);
        ensureRemote(repoPath, remote, remoteUrl);
        fetchNotes(repoPath, remote);
    }

    /**
     * Removes a local repository directory used for notes operations.
     *
     * @param repoPath repository root
     * @throws GitException if deletion fails
     */
    @Override
    public void removeRepository(Path repoPath) throws GitException {
        if (!Files.exists(repoPath)) {
            return;
        }
        deleteDirectoryRecursively(repoPath);
    }

    /**
     * Appends one NDJSON entry to a stream ref.
     *
     * @param repoPath repository root
     * @param streamRef fully-qualified stream ref
     * @param entryJson one JSON object serialized as one NDJSON line
     * @throws GitException if stream read or write fails
     */
    @Override
    public void appendToStream(Path repoPath, String streamRef, String entryJson) throws GitException {
        String entryLine = normalizeEntryLine(entryJson);
        String existingContent = readStreamContent(repoPath, streamRef);
        String nextContent = appendEntry(existingContent, entryLine);
        String blobSha = createBlob(repoPath, nextContent);
        updateRef(repoPath, streamRef, blobSha);
    }

    /**
     * Reads all NDJSON lines from a stream ref.
     *
     * @param repoPath repository root
     * @param streamRef fully-qualified stream ref
     * @return ordered non-empty NDJSON lines
     * @throws GitException if stream read fails
     */
    @Override
    public List<String> readStreamEntries(Path repoPath, String streamRef) throws GitException {
        String content = readStreamContent(repoPath, streamRef);
        if (content.isEmpty()) {
            return List.of();
        }
        String[] lines = content.split("\\R");
        List<String> entries = new ArrayList<>();
        for (String line : lines) {
            if (!line.trim().isEmpty()) {
                entries.add(line);
            }
        }
        return entries;
    }

    /**
     * Fetches all review-note refs from the remote using union merge strategy.
     *
     * @param repoPath repository root
     * @param remote remote name
     * @throws GitException if fetch fails
     */
    @Override
    public void fetchNotes(Path repoPath, String remote) throws GitException {
        run(repoPath,
            List.of("git", "-c", "notes.mergeStrategy=union",
                    "fetch", remote, FETCH_REFSPEC));
    }

    /**
     * Pushes all local review-note refs to the remote.
     *
     * @param repoPath repository root
     * @param remote remote name
     * @throws GitException if push fails
     */
    @Override
    public void pushNotes(Path repoPath, String remote) throws GitException {
        run(repoPath, List.of("git", "push", remote, PUSH_REFSPEC));
    }

    /**
     * Creates a loose blob object in the repository from the supplied content.
     *
     * @param repoPath    repository root
     * @param content UTF-8 stream content to store as a blob
     * @return the 40-character SHA-1 of the newly created blob
     * @throws GitException if the hash-object command fails
     */
    private String createBlob(Path repoPath, String content) throws GitException {
        List<String> command = List.of("git", "hash-object", "-w", "--stdin");
        try {
            Process process = buildProcess(repoPath, command).start();
            writeStdin(process, content);
            CommandResult result = waitForResult(process);
            String sha = result.stdout.trim();
            int exitCode = process.waitFor();
            checkExitCode(command, exitCode, result.stderr);
            return sha;
        } catch (IOException | InterruptedException e) {
            if (e instanceof InterruptedException) {
                Thread.currentThread().interrupt();
            }
            throw new GitException("Failed to create blob: " + e.getMessage(), e);
        }
    }

    /**
     * Points the given fully-qualified ref at a specific object SHA.
     *
     * @param repoPath repository root
     * @param fullRef  the ref to create or overwrite
     * @param objectSha the target object SHA
     * @throws GitException if the update-ref command fails
     */
    private void updateRef(Path repoPath, String fullRef, String objectSha) throws GitException {
        run(repoPath, List.of("git", "update-ref", fullRef, objectSha));
    }

    /**
     * Runs a git command, waits for it to complete and throws if the exit code is non-zero.
     *
     * @param repoPath  repository root used as working directory
     * @param command   full command including {@code git} as the first element
     * @throws GitException if the process exits with a non-zero code or cannot be started
     */
    private void run(Path repoPath, List<String> command) throws GitException {
        try {
            Process process = buildProcess(repoPath, command).start();
            CommandResult result = waitForResult(process);
            int exitCode = process.waitFor();
            checkExitCode(command, exitCode, result.stderr);
        } catch (IOException | InterruptedException e) {
            if (e instanceof InterruptedException) {
                Thread.currentThread().interrupt();
            }
            throw new GitException("Failed to execute " + commandName(command) + ": " + e.getMessage(), e);
        }
    }

    private String runForStdout(Path repoPath, List<String> command) throws GitException {
        try {
            Process process = buildProcess(repoPath, command).start();
            CommandResult result = waitForResult(process);
            int exitCode = process.waitFor();
            checkExitCode(command, exitCode, result.stderr);
            return result.stdout;
        } catch (IOException | InterruptedException e) {
            if (e instanceof InterruptedException) {
                Thread.currentThread().interrupt();
            }
            throw new GitException("Failed to execute " + commandName(command) + ": " + e.getMessage(), e);
        }
    }

    private boolean refExists(Path repoPath, String ref) throws GitException {
        List<String> command = List.of("git", "show-ref", "--verify", "--quiet", ref);
        try {
            Process process = buildProcess(repoPath, command).start();
            CommandResult result = waitForResult(process);
            int exitCode = process.waitFor();
            if (exitCode == 0) {
                return true;
            }
            if (exitCode == 1) {
                return false;
            }
            throw new GitException(
                    "git " + commandName(command) + " failed (exit " + exitCode + "): " + result.stderr.trim(),
                    exitCode);
        } catch (IOException | InterruptedException e) {
            if (e instanceof InterruptedException) {
                Thread.currentThread().interrupt();
            }
            throw new GitException("Failed to execute " + commandName(command) + ": " + e.getMessage(), e);
        }
    }

    private String readStreamContent(Path repoPath, String streamRef) throws GitException {
        if (!refExists(repoPath, streamRef)) {
            return "";
        }
        return runForStdout(repoPath, List.of("git", "cat-file", "-p", streamRef));
    }

    private String appendEntry(String existingContent, String entryLine) {
        if (existingContent.isEmpty()) {
            return entryLine + "\n";
        }
        if (existingContent.endsWith("\n")) {
            return existingContent + entryLine + "\n";
        }
        return existingContent + "\n" + entryLine + "\n";
    }

    private String normalizeEntryLine(String entryJson) throws GitException {
        String normalized = entryJson.replace("\r", "").replace("\n", "").trim();
        if (normalized.isEmpty()) {
            throw new GitException("Stream entry cannot be empty", -1);
        }
        return normalized;
    }

    private void ensureDirectory(Path repoPath) throws GitException {
        try {
            Files.createDirectories(repoPath);
        } catch (IOException e) {
            throw new GitException("Failed to create repository directory: " + e.getMessage(), e);
        }
    }

    private void ensureGitRepository(Path repoPath) throws GitException {
        if (Files.isDirectory(repoPath.resolve(".git"))) {
            return;
        }
        run(repoPath, List.of("git", "init"));
    }

    private void ensureRemote(Path repoPath, String remote, String remoteUrl) throws GitException {
        if (hasRemote(repoPath, remote)) {
            run(repoPath, List.of("git", "remote", "set-url", remote, remoteUrl));
            return;
        }
        run(repoPath, List.of("git", "remote", "add", remote, remoteUrl));
    }

    private boolean hasRemote(Path repoPath, String remote) throws GitException {
        String remotes = runForStdout(repoPath, List.of("git", "remote"));
        String[] lines = remotes.split("\\R");
        for (String line : lines) {
            if (line.trim().equals(remote)) {
                return true;
            }
        }
        return false;
    }

    private void deleteDirectoryRecursively(Path repoPath) throws GitException {
        try (Stream<Path> paths = Files.walk(repoPath)) {
            paths.sorted(Comparator.reverseOrder()).forEach(path -> {
                try {
                    Files.deleteIfExists(path);
                } catch (IOException e) {
                    throw new RuntimeException(e);
                }
            });
        } catch (RuntimeException e) {
            if (e.getCause() instanceof IOException) {
                throw new GitException("Failed to remove repository: " + e.getCause().getMessage(), e.getCause());
            }
            throw e;
        } catch (IOException e) {
            throw new GitException("Failed to remove repository: " + e.getMessage(), e);
        }
    }

    private ProcessBuilder buildProcess(Path repoPath, List<String> command) {
        ProcessBuilder pb = new ProcessBuilder(command);
        pb.directory(repoPath.toFile());
        pb.redirectErrorStream(false);
        return pb;
    }

    private void writeStdin(Process process, String content) throws IOException {
        try (OutputStream stdin = process.getOutputStream()) {
            stdin.write(content.getBytes(StandardCharsets.UTF_8));
        }
    }

    private CommandResult waitForResult(Process process) throws IOException {
        String stdout = readStream(new BufferedReader(
                new InputStreamReader(process.getInputStream(), StandardCharsets.UTF_8)));
        String stderr = readStream(new BufferedReader(
                new InputStreamReader(process.getErrorStream(), StandardCharsets.UTF_8)));
        return new CommandResult(stdout, stderr);
    }

    private String readStream(BufferedReader reader) throws IOException {
        StringBuilder sb = new StringBuilder();
        String line;
        while ((line = reader.readLine()) != null) {
            sb.append(line).append("\n");
        }
        return sb.toString();
    }

    private void checkExitCode(List<String> command, int exitCode, String output) throws GitException {
        if (exitCode != 0) {
            throw new GitException(
                    "git " + commandName(command) + " failed (exit " + exitCode + "): " + output.trim(),
                    exitCode);
        }
    }

    private String commandName(List<String> command) {
        return command.size() > 1 ? command.get(1) : command.get(0);
    }

    private static class CommandResult {
        private final String stdout;
        private final String stderr;

        private CommandResult(String stdout, String stderr) {
            this.stdout = stdout;
            this.stderr = stderr;
        }
    }
}

package com.kalynx.serverlessreviewtool.git;

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.io.OutputStream;
import java.nio.charset.StandardCharsets;
import java.nio.file.Path;
import java.util.List;

/**
 * GitProcess - Utility for running git commands as external processes.
 *
 * <p>All methods operate relative to the provided repository path so that
 * multiple repositories can be managed concurrently without changing the JVM
 * working directory.
 */
class GitProcess {

    private GitProcess() {
    }

    /**
     * Runs a git command and waits for completion, discarding stdout.
     *
     * @param repoPath absolute path used as the working directory
     * @param command  full command list with {@code git} as the first element
     * @throws GitException if the process exits with a non-zero code or cannot start
     */
    static void run(Path repoPath, List<String> command) throws GitException {
        try {
            Process process = build(repoPath, command).start();
            Result result = await(process);
            checkExitCode(command, process.waitFor(), result.stderr);
        } catch (IOException | InterruptedException e) {
            handleProcessException(e, command);
        }
    }

    /**
     * Runs a git command and returns its stdout output.
     *
     * @param repoPath absolute path used as the working directory
     * @param command  full command list with {@code git} as the first element
     * @return stdout content as a string
     * @throws GitException if the process exits with a non-zero code or cannot start
     */
    static String runForStdout(Path repoPath, List<String> command) throws GitException {
        try {
            Process process = build(repoPath, command).start();
            Result result = await(process);
            checkExitCode(command, process.waitFor(), result.stderr);
            return result.stdout;
        } catch (IOException | InterruptedException e) {
            handleProcessException(e, command);
            return "";
        }
    }

    /**
     * Runs a git command and returns the exit code without throwing on failure.
     *
     * @param repoPath absolute path used as the working directory
     * @param command  full command list with {@code git} as the first element
     * @return the process exit code
     * @throws GitException if the process cannot start
     */
    static int runForExitCode(Path repoPath, List<String> command) throws GitException {
        try {
            Process process = build(repoPath, command).start();
            await(process);
            return process.waitFor();
        } catch (IOException | InterruptedException e) {
            handleProcessException(e, command);
            return -1;
        }
    }

    /**
     * Writes content to the stdin of a running process.
     *
     * @param process the target process
     * @param content UTF-8 content to write
     * @throws IOException if writing fails
     */
    static void writeStdin(Process process, String content) throws IOException {
        try (OutputStream stdin = process.getOutputStream()) {
            stdin.write(content.getBytes(StandardCharsets.UTF_8));
        }
    }

    /**
     * Starts a process for a git command without waiting for completion.
     *
     * @param repoPath absolute path used as the working directory
     * @param command  full command list
     * @return the started process
     * @throws IOException if the process cannot be started
     */
    static Process start(Path repoPath, List<String> command) throws IOException {
        return build(repoPath, command).start();
    }

    /**
     * Reads stdout and stderr from the process and returns them as a result.
     *
     * @param process the process to read from
     * @return a result containing stdout and stderr content
     * @throws IOException if reading fails
     */
    static Result await(Process process) throws IOException {
        String stdout = readStream(new BufferedReader(
                new InputStreamReader(process.getInputStream(), StandardCharsets.UTF_8)));
        String stderr = readStream(new BufferedReader(
                new InputStreamReader(process.getErrorStream(), StandardCharsets.UTF_8)));
        return new Result(stdout, stderr);
    }

    /**
     * Throws a {@link GitException} if the exit code is non-zero.
     *
     * @param command  the command that was run
     * @param exitCode the process exit code
     * @param output   stderr output to include in the exception message
     * @throws GitException if exitCode is not zero
     */
    static void checkExitCode(List<String> command, int exitCode, String output) throws GitException {
        if (exitCode != 0) {
            throw new GitException(
                    "git " + name(command) + " failed (exit " + exitCode + "): " + output.trim(),
                    exitCode);
        }
    }

    /**
     * Returns the displayable command name for use in error messages.
     *
     * @param command full command list
     * @return subcommand name or the first element if the list has only one entry
     */
    static String name(List<String> command) {
        return command.size() > 1 ? command.get(1) : command.get(0);
    }

    private static ProcessBuilder build(Path repoPath, List<String> command) {
        ProcessBuilder pb = new ProcessBuilder(command);
        pb.directory(repoPath.toFile());
        pb.redirectErrorStream(false);
        return pb;
    }

    private static String readStream(BufferedReader reader) throws IOException {
        StringBuilder sb = new StringBuilder();
        String line;
        while ((line = reader.readLine()) != null) {
            sb.append(line).append("\n");
        }
        return sb.toString();
    }

    private static void handleProcessException(Exception e, List<String> command) throws GitException {
        if (e instanceof InterruptedException) {
            Thread.currentThread().interrupt();
        }
        throw new GitException("Failed to execute " + name(List.of("git", name(List.copyOf(command)))) + ": " + e.getMessage(), e);
    }

    /**
     * Holds the stdout and stderr output captured from a process.
     */
    static class Result {
        final String stdout;
        final String stderr;

        Result(String stdout, String stderr) {
            this.stdout = stdout;
            this.stderr = stderr;
        }
    }
}

package com.kalynx.serverlessreviewtool.theme.components;

import com.kalynx.serverlessreviewtool.theme.Theme;
import com.kalynx.serverlessreviewtool.theme.ThemeManager;

import javax.swing.*;
import javax.swing.plaf.basic.BasicComboBoxEditor;
import javax.swing.plaf.basic.BasicComboBoxUI;
import javax.swing.text.AttributeSet;
import javax.swing.text.BadLocationException;
import javax.swing.text.PlainDocument;
import java.awt.*;
import java.awt.event.KeyAdapter;
import java.awt.event.KeyEvent;
import java.util.ArrayList;
import java.util.List;

/**
 * ThemedSearchableComboBox - A combo box that filters items as you type.
 *
 * Behaves like a traditional combo box but allows real-time filtering of items
 * by typing in the text field. The selected value remains visible in the combo box.
 */
public class ThemedSearchableComboBox extends JComboBox<String> {

    private final ThemeManager themeManager;
    private final List<String> allItems;
    private final DefaultComboBoxModel<String> model;
    private boolean isFiltering = false;
    private boolean shouldCommitSelection = false;

    /**
     * Creates a searchable combo box with the provided list of items.
     *
     * @param items the list of items to choose from
     */
    public ThemedSearchableComboBox(List<String> items) {
        super();
        this.themeManager = ThemeManager.getInstance();
        this.allItems = new ArrayList<>(items);
        this.model = new DefaultComboBoxModel<>();

        setModel(model);
        setEditable(true);

        for (String item : allItems) {
            model.addElement(item);
        }

        setEditor(new SearchableComboBoxEditor());
        setUI(new ThemedComboBoxUI());
        applyTheme();
        setupFiltering();
    }

    private void setupFiltering() {
        JTextField editorComponent = (JTextField) getEditor().getEditorComponent();
        editorComponent.setDocument(new FilterDocument());

        setSelectedItem(null);

        editorComponent.addKeyListener(new KeyAdapter() {
            @Override
            public void keyPressed(KeyEvent e) {
                if (e.getKeyCode() == KeyEvent.VK_ENTER) {
                    if (isPopupVisible() && getSelectedItem() != null) {
                        commitSelection();
                        setPopupVisible(false);
                        e.consume();
                    }
                } else if (e.getKeyCode() == KeyEvent.VK_ESCAPE) {
                    setPopupVisible(false);
                    e.consume();
                }
            }
        });

        addPopupMenuListener(new javax.swing.event.PopupMenuListener() {
            @Override
            public void popupMenuWillBecomeVisible(javax.swing.event.PopupMenuEvent e) {}

            @Override
            public void popupMenuWillBecomeInvisible(javax.swing.event.PopupMenuEvent e) {
                if (shouldCommitSelection) {
                    SwingUtilities.invokeLater(() -> {
                        commitSelection();
                        shouldCommitSelection = false;
                    });
                }
            }

            @Override
            public void popupMenuCanceled(javax.swing.event.PopupMenuEvent e) {
                shouldCommitSelection = false;
            }
        });

        addActionListener(e -> {
            if (isPopupVisible() && getSelectedItem() != null) {
                shouldCommitSelection = true;
            }
        });
    }

    private void commitSelection() {
        Object selected = getSelectedItem();
        if (selected != null && !isFiltering) {
            isFiltering = true;
            try {
                JTextField editor = (JTextField) getEditor().getEditorComponent();
                editor.setText(selected.toString());
                editor.setCaretPosition(editor.getText().length());
            } finally {
                isFiltering = false;
            }
        }
    }

    private void filterItems(String filter) {
        if (isFiltering) {
            return;
        }

        isFiltering = true;
        try {
            String currentText = filter.toLowerCase().trim();
            JTextField editorComponent = (JTextField) getEditor().getEditorComponent();
            int caretPos = editorComponent.getCaretPosition();

            model.removeAllElements();

            if (currentText.isEmpty()) {
                for (String item : allItems) {
                    model.addElement(item);
                }
                setPopupVisible(false);
            } else {
                for (String item : allItems) {
                    if (item.toLowerCase().contains(currentText)) {
                        model.addElement(item);
                    }
                }

                if (model.getSize() > 0) {
                    setPopupVisible(true);
                } else {
                    setPopupVisible(false);
                }
            }

            setSelectedItem(null);

            editorComponent.setText(filter);
            editorComponent.setCaretPosition(Math.min(caretPos, filter.length()));
        } finally {
            isFiltering = false;
        }
    }

    private void applyTheme() {
        Theme theme = themeManager.getCurrentTheme();
        setFont(new Font("Segoe UI", Font.PLAIN, themeManager.scale(12)));
        setBackground(theme.getInputBackground());
        setForeground(theme.getForegroundColor());
        setRenderer(new SearchableComboBoxRenderer());
    }

    @Override
    public void updateUI() {
        if (themeManager != null) {
            setUI(new ThemedComboBoxUI());
            SwingUtilities.invokeLater(this::applyTheme);
        } else {
            super.updateUI();
        }
    }

    @Override
    protected void paintComponent(Graphics g) {
        if (themeManager != null) {
            Theme theme = themeManager.getCurrentTheme();
            setBackground(theme.getInputBackground());
            setForeground(theme.getForegroundColor());
        }
        super.paintComponent(g);
    }

    private class FilterDocument extends PlainDocument {
        @Override
        public void insertString(int offset, String str, AttributeSet attr) throws BadLocationException {
            super.insertString(offset, str, attr);
            if (!isFiltering) {
                try {
                    String text = getText(0, getLength());
                    SwingUtilities.invokeLater(() -> {
                        if (!isFiltering) {
                            filterItems(text);
                        }
                    });
                } catch (BadLocationException e) {
                    // Ignore
                }
            }
        }

        @Override
        public void remove(int offset, int length) throws BadLocationException {
            super.remove(offset, length);
            if (!isFiltering) {
                try {
                    String text = getText(0, getLength());
                    SwingUtilities.invokeLater(() -> {
                        if (!isFiltering) {
                            filterItems(text);
                        }
                    });
                } catch (BadLocationException e) {
                    // Ignore
                }
            }
        }
    }

    private class SearchableComboBoxEditor extends BasicComboBoxEditor {
        @Override
        protected JTextField createEditorComponent() {
            JTextField editor = new JTextField();
            editor.setBorder(BorderFactory.createEmptyBorder(
                themeManager.scale(4),
                themeManager.scale(8),
                themeManager.scale(4),
                themeManager.scale(8)
            ));
            return editor;
        }

        @Override
        public void setItem(Object item) {
            if (!isFiltering && item != null) {
                editor.setText(item.toString());
                editor.setCaretPosition(editor.getText().length());
            }
        }
    }

    private class ThemedComboBoxUI extends BasicComboBoxUI {
        @Override
        protected JButton createArrowButton() {
            JButton button = new JButton("▼") {
                @Override
                public void paintComponent(Graphics g) {
                    Theme theme = themeManager.getCurrentTheme();
                    g.setColor(theme.getInputBackground());
                    g.fillRect(0, 0, getWidth(), getHeight());
                    g.setColor(theme.getForegroundColor());
                    g.setFont(getFont());
                    FontMetrics fm = g.getFontMetrics();
                    String text = getText();
                    int x = (getWidth() - fm.stringWidth(text)) / 2;
                    int y = ((getHeight() - fm.getHeight()) / 2) + fm.getAscent();
                    g.drawString(text, x, y);
                }
            };

            button.setName("ComboBox.arrowButton");
            button.setFont(new Font("Segoe UI", Font.PLAIN, themeManager.scale(10)));
            button.setBorder(BorderFactory.createEmptyBorder());
            button.setFocusPainted(false);
            button.setContentAreaFilled(false);
            button.setOpaque(false);
            button.setMargin(new Insets(0, 0, 0, 0));
            button.setCursor(Cursor.getPredefinedCursor(Cursor.HAND_CURSOR));

            return button;
        }

        @Override
        public void paintCurrentValueBackground(Graphics g, Rectangle bounds, boolean hasFocus) {
            Theme theme = themeManager.getCurrentTheme();
            g.setColor(theme.getInputBackground());
            g.fillRect(bounds.x, bounds.y, bounds.width, bounds.height);
        }
    }

    private class SearchableComboBoxRenderer extends DefaultListCellRenderer {
        @Override
        public Component getListCellRendererComponent(JList<?> list, Object value,
                                                      int index, boolean isSelected, boolean cellHasFocus) {
            Theme theme = themeManager.getCurrentTheme();

            if (list != null) {
                list.setBackground(theme.getInputBackground());
                list.setForeground(theme.getForegroundColor());
                list.setSelectionBackground(theme.getAccentColor());
                list.setSelectionForeground(Color.WHITE);
            }

            JLabel label = (JLabel) super.getListCellRendererComponent(list, value, index, isSelected, cellHasFocus);
            label.setFont(new Font("Segoe UI", Font.PLAIN, themeManager.scale(12)));
            label.setBorder(BorderFactory.createEmptyBorder(
                themeManager.scale(6),
                themeManager.scale(8),
                themeManager.scale(6),
                themeManager.scale(8)
            ));
            label.setOpaque(true);

            if (isSelected) {
                label.setBackground(theme.getAccentColor());
                label.setForeground(Color.WHITE);
            } else {
                label.setBackground(theme.getInputBackground());
                label.setForeground(theme.getForegroundColor());
            }

            return label;
        }
    }
}

package com.kalynx.serverlessreviewtool.theme.components;

import com.kalynx.serverlessreviewtool.theme.Theme;
import com.kalynx.serverlessreviewtool.theme.ThemeManager;

import javax.swing.*;
import javax.swing.plaf.basic.BasicComboBoxEditor;
import javax.swing.plaf.basic.BasicComboBoxUI;
import javax.swing.text.AttributeSet;
import javax.swing.text.BadLocationException;
import javax.swing.text.PlainDocument;
import java.awt.*;
import java.awt.event.KeyAdapter;
import java.awt.event.KeyEvent;
import java.util.ArrayList;
import java.util.List;

/**
 * ThemedSearchableComboBox - A combo box that filters items as you type.
 *
 * Behaves like a traditional combo box but allows real-time filtering of items
 * by typing in the text field. The selected value remains visible in the combo box.
 */
public class ThemedSearchableComboBox extends JComboBox<String> {

    private final ThemeManager themeManager;
    private final List<String> allItems;
    private final DefaultComboBoxModel<String> model;
    private boolean isFiltering = false;
    private boolean allowEditorUpdate = false;

    /**
     * Creates a searchable combo box with the provided list of items.
     *
     * @param items the list of items to choose from
     */
    public ThemedSearchableComboBox(List<String> items) {
        super();
        this.themeManager = ThemeManager.getInstance();
        this.allItems = new ArrayList<>(items);
        this.model = new DefaultComboBoxModel<>();

        setModel(model);
        setEditable(true);

        for (String item : allItems) {
            model.addElement(item);
        }

        setEditor(new SearchableComboBoxEditor());
        setUI(new ThemedComboBoxUI());
        applyTheme();
        setupFiltering();
    }

    private void setupFiltering() {
        JTextField editorComponent = (JTextField) getEditor().getEditorComponent();
        editorComponent.setDocument(new FilterDocument());

        setSelectedItem(null);

        editorComponent.addKeyListener(new KeyAdapter() {
            @Override
            public void keyPressed(KeyEvent e) {
                if (e.getKeyCode() == KeyEvent.VK_ENTER) {
                    if (isPopupVisible() && getSelectedItem() != null) {
                        commitSelection();
                        setPopupVisible(false);
                        e.consume();
                    }
                } else if (e.getKeyCode() == KeyEvent.VK_ESCAPE) {
                    setPopupVisible(false);
                    e.consume();
                }
            }
        });

        JList<?> list = getListFromPopup();
        if (list != null) {
            list.addMouseListener(new java.awt.event.MouseAdapter() {
                @Override
                public void mouseClicked(java.awt.event.MouseEvent e) {
                    if (e.getClickCount() == 1) {
                        int index = list.locationToIndex(e.getPoint());
                        if (index >= 0) {
                            list.setSelectedIndex(index);
                            SwingUtilities.invokeLater(() -> {
                                commitSelection();
                                setPopupVisible(false);
                            });
                        }
                    }
                }
            });
        }
    }

    private JList<?> getListFromPopup() {
        try {
            for (int i = 0; i < getComponentCount(); i++) {
                Component comp = getComponent(i);
                if (comp instanceof JPopupMenu) {
                    JPopupMenu popup = (JPopupMenu) comp;
                    if (popup.getComponentCount() > 0) {
                        Component popupComp = popup.getComponent(0);
                        if (popupComp instanceof JScrollPane) {
                            JScrollPane scroll = (JScrollPane) popupComp;
                            Component view = scroll.getViewport().getView();
                            if (view instanceof JList) {
                                return (JList<?>) view;
                            }
                        }
                    }
                }
            }
        } catch (Exception ex) {
            // Ignore
        }
        return null;
    }

    private void commitSelection() {
        Object selected = getSelectedItem();
        if (selected != null && !isFiltering) {
            allowEditorUpdate = true;
            isFiltering = true;
            try {
                JTextField editor = (JTextField) getEditor().getEditorComponent();
                editor.setText(selected.toString());
                editor.setCaretPosition(editor.getText().length());
            } finally {
                isFiltering = false;
                allowEditorUpdate = false;
            }
        }
    }

    private void filterItems(String filter) {
        if (isFiltering) {
            return;
        }

        isFiltering = true;
        try {
            String currentText = filter.toLowerCase().trim();
            JTextField editorComponent = (JTextField) getEditor().getEditorComponent();
            int caretPos = editorComponent.getCaretPosition();

            model.removeAllElements();

            if (currentText.isEmpty()) {
                for (String item : allItems) {
                    model.addElement(item);
                }
                setPopupVisible(false);
            } else {
                for (String item : allItems) {
                    if (item.toLowerCase().contains(currentText)) {
                        model.addElement(item);
                    }
                }

                if (model.getSize() > 0) {
                    setPopupVisible(true);
                } else {
                    setPopupVisible(false);
                }
            }

            setSelectedItem(null);

            editorComponent.setText(filter);
            editorComponent.setCaretPosition(Math.min(caretPos, filter.length()));
        } finally {
            isFiltering = false;
        }
    }

    private void applyTheme() {
        Theme theme = themeManager.getCurrentTheme();
        setFont(new Font("Segoe UI", Font.PLAIN, themeManager.scale(12)));
        setBackground(theme.getInputBackground());
        setForeground(theme.getForegroundColor());
        setRenderer(new SearchableComboBoxRenderer());
    }

    @Override
    public void updateUI() {
        if (themeManager != null) {
            setUI(new ThemedComboBoxUI());
            SwingUtilities.invokeLater(this::applyTheme);
        } else {
            super.updateUI();
        }
    }

    @Override
    protected void paintComponent(Graphics g) {
        if (themeManager != null) {
            Theme theme = themeManager.getCurrentTheme();
            setBackground(theme.getInputBackground());
            setForeground(theme.getForegroundColor());
        }
        super.paintComponent(g);
    }

    private class FilterDocument extends PlainDocument {
        @Override
        public void insertString(int offset, String str, AttributeSet attr) throws BadLocationException {
            super.insertString(offset, str, attr);
            if (!isFiltering) {
                try {
                    String text = getText(0, getLength());
                    SwingUtilities.invokeLater(() -> {
                        if (!isFiltering) {
                            filterItems(text);
                        }
                    });
                } catch (BadLocationException e) {
                    // Ignore
                }
            }
        }

        @Override
        public void remove(int offset, int length) throws BadLocationException {
            super.remove(offset, length);
            if (!isFiltering) {
                try {
                    String text = getText(0, getLength());
                    SwingUtilities.invokeLater(() -> {
                        if (!isFiltering) {
                            filterItems(text);
                        }
                    });
                } catch (BadLocationException e) {
                    // Ignore
                }
            }
        }
    }

    private class SearchableComboBoxEditor extends BasicComboBoxEditor {
        @Override
        protected JTextField createEditorComponent() {
            JTextField editor = new JTextField();
            editor.setBorder(BorderFactory.createEmptyBorder(
                themeManager.scale(4),
                themeManager.scale(8),
                themeManager.scale(4),
                themeManager.scale(8)
            ));
            return editor;
        }

        @Override
        public void setItem(Object item) {
            if (allowEditorUpdate && !isFiltering && item != null) {
                editor.setText(item.toString());
                editor.setCaretPosition(editor.getText().length());
            }
        }
    }

    private class ThemedComboBoxUI extends BasicComboBoxUI {
        @Override
        protected JButton createArrowButton() {
            JButton button = new JButton("▼") {
                @Override
                public void paintComponent(Graphics g) {
                    Theme theme = themeManager.getCurrentTheme();
                    g.setColor(theme.getInputBackground());
                    g.fillRect(0, 0, getWidth(), getHeight());
                    g.setColor(theme.getForegroundColor());
                    g.setFont(getFont());
                    FontMetrics fm = g.getFontMetrics();
                    String text = getText();
                    int x = (getWidth() - fm.stringWidth(text)) / 2;
                    int y = ((getHeight() - fm.getHeight()) / 2) + fm.getAscent();
                    g.drawString(text, x, y);
                }
            };

            button.setName("ComboBox.arrowButton");
            button.setFont(new Font("Segoe UI", Font.PLAIN, themeManager.scale(10)));
            button.setBorder(BorderFactory.createEmptyBorder());
            button.setFocusPainted(false);
            button.setContentAreaFilled(false);
            button.setOpaque(false);
            button.setMargin(new Insets(0, 0, 0, 0));
            button.setCursor(Cursor.getPredefinedCursor(Cursor.HAND_CURSOR));

            return button;
        }

        @Override
        public void paintCurrentValueBackground(Graphics g, Rectangle bounds, boolean hasFocus) {
            Theme theme = themeManager.getCurrentTheme();
            g.setColor(theme.getInputBackground());
            g.fillRect(bounds.x, bounds.y, bounds.width, bounds.height);
        }
    }

    private class SearchableComboBoxRenderer extends DefaultListCellRenderer {
        @Override
        public Component getListCellRendererComponent(JList<?> list, Object value,
                                                      int index, boolean isSelected, boolean cellHasFocus) {
            Theme theme = themeManager.getCurrentTheme();

            if (list != null) {
                list.setBackground(theme.getInputBackground());
                list.setForeground(theme.getForegroundColor());
                list.setSelectionBackground(theme.getAccentColor());
                list.setSelectionForeground(Color.WHITE);
            }

            JLabel label = (JLabel) super.getListCellRendererComponent(list, value, index, isSelected, cellHasFocus);
            label.setFont(new Font("Segoe UI", Font.PLAIN, themeManager.scale(12)));
            label.setBorder(BorderFactory.createEmptyBorder(
                themeManager.scale(6),
                themeManager.scale(8),
                themeManager.scale(6),
                themeManager.scale(8)
            ));
            label.setOpaque(true);

            if (isSelected) {
                label.setBackground(theme.getAccentColor());
                label.setForeground(Color.WHITE);
            } else {
                label.setBackground(theme.getInputBackground());
                label.setForeground(theme.getForegroundColor());
            }

            return label;
        }
    }
}

