package com.kalynx.serverlessreviewtool.ui.models.mainpanels.reviewpanel;

import com.kalynx.serverlessreviewtool.models.ReviewComment;
import com.kalynx.serverlessreviewtool.models.ReviewerInfo;
import com.kalynx.serverlessreviewtool.models.ReviewerStatus;
import com.kalynx.serverlessreviewtool.models.review.ReviewStatus;
import com.kalynx.serverlessreviewtool.swingextensions.ComponentModel;

import java.util.ArrayList;
import java.util.List;

public class ReviewsModel {

    public final ComponentModel<String> reviewId = new ComponentModel<>();
    public final ComponentModel<String> title = new ComponentModel<>();
    public final ComponentModel<String> summary = new ComponentModel<>();
    public final ComponentModel<String> author = new ComponentModel<>();
    public final ComponentModel<ReviewStatus> status = new ComponentModel<>();

    public final ComponentModel<List<String>> commits = new ComponentModel<>();
    public final ComponentModel<List<ReviewerInfo>> reviewers = new ComponentModel<>();
    public final ComponentModel<List<ReviewComment>> comments = new ComponentModel<>();

    public final ComponentModel<String> selectedRepository = new ComponentModel<>();
    public final ComponentModel<String> selectedFile = new ComponentModel<>();
    public final ComponentModel<String> selectedCommit = new ComponentModel<>();

    public final ComponentModel<Boolean> isLoading = new ComponentModel<>();
    public final ComponentModel<String> errorMessage = new ComponentModel<>();

    public ReviewsModel() {
        initializeDefaults();
    }

    private void initializeDefaults() {
        reviewId.setValue("");
        title.setValue("");
        summary.setValue("");
        author.setValue("");
        status.setValue(ReviewStatus.PENDING);
        commits.setValue(new ArrayList<>());
        reviewers.setValue(new ArrayList<>());
        comments.setValue(new ArrayList<>());
        selectedRepository.setValue("");
        selectedFile.setValue("");
        selectedCommit.setValue("");
        isLoading.setValue(false);
        errorMessage.setValue("");
    }

    public void clear() {
        initializeDefaults();
    }

    public void loadReviewData(String reviewId, String title, String summary, String author,
                               ReviewStatus status, List<String> commits,
                               List<ReviewerInfo> reviewers, List<ReviewComment> comments) {
        this.reviewId.setValue(reviewId);
        this.title.setValue(title);
        this.summary.setValue(summary);
        this.author.setValue(author);
        this.status.setValue(status);
        this.commits.setValue(new ArrayList<>(commits));
        this.reviewers.setValue(new ArrayList<>(reviewers));
        this.comments.setValue(new ArrayList<>(comments));
    }

    public void addReviewer(ReviewerInfo reviewer) {
        List<ReviewerInfo> current = new ArrayList<>(reviewers.getValue());
        current.add(reviewer);
        reviewers.setValue(current);
    }

    public void removeReviewer(ReviewerInfo reviewer) {
        List<ReviewerInfo> current = new ArrayList<>(reviewers.getValue());
        current.remove(reviewer);
        reviewers.setValue(current);
    }

    public void updateReviewerStatus(String reviewerName, ReviewerStatus newStatus) {
        List<ReviewerInfo> current = new ArrayList<>(reviewers.getValue());
        current.stream()
            .filter(r -> r.getName().equals(reviewerName))
            .findFirst()
            .ifPresent(r -> {
                r.setStatus(newStatus);
                reviewers.setValue(current);
            });
    }

    public void addComment(ReviewComment comment) {
        List<ReviewComment> current = new ArrayList<>(comments.getValue());
        current.add(comment);
        comments.setValue(current);
    }

    public void removeComment(ReviewComment comment) {
        List<ReviewComment> current = new ArrayList<>(comments.getValue());
        current.remove(comment);
        comments.setValue(current);
    }

    public List<ReviewComment> getCommentsForFile(String filePath) {
        return comments.getValue().stream()
            .filter(c -> c.getFilePath().equals(filePath))
            .toList();
    }

    public void setLoadingState(boolean loading) {
        isLoading.setValue(loading);
        if (loading) {
            errorMessage.setValue("");
        }
    }

    public void setError(String error) {
        errorMessage.setValue(error);
        isLoading.setValue(false);
    }

    public boolean hasReview() {
        return reviewId.getValue() != null && !reviewId.getValue().isEmpty();
    }

    public boolean isReviewOpen() {
        ReviewStatus currentStatus = status.getValue();
        return currentStatus == ReviewStatus.PENDING ||
               currentStatus == ReviewStatus.IN_PROGRESS ||
               currentStatus == ReviewStatus.CHANGES_REQUESTED;
    }

    public boolean isReviewClosed() {
        ReviewStatus currentStatus = status.getValue();
        return currentStatus == ReviewStatus.APPROVED ||
               currentStatus == ReviewStatus.REJECTED;
    }

    public int getApprovedReviewersCount() {
        return (int) reviewers.getValue().stream()
            .filter(r -> r.getStatus() == ReviewerStatus.APPROVED)
            .count();
    }

    public int getPendingReviewersCount() {
        return (int) reviewers.getValue().stream()
            .filter(r -> r.getStatus() == ReviewerStatus.REVIEWING)
            .count();
    }

    public int getUnresolvedCommentsCount() {
        return (int) comments.getValue().stream()
            .filter(c -> !c.isResolved())
            .count();
    }

    public void updateTitle(String newTitle) {
        title.setValue(newTitle);
    }

    public void updateSummary(String newSummary) {
        summary.setValue(newSummary);
    }

    public void updateStatus(ReviewStatus newStatus) {
        status.setValue(newStatus);
    }
}
